import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { MagnifyingGlassIcon, StarIcon, PhoneIcon, MapPinIcon } from '@heroicons/react/24/solid';
import { restaurantAPI } from '../services/api';

const CustomerDashboard = ({ user, onLogout }) => {
  const [restaurants, setRestaurants] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterType, setFilterType] = useState('all');
  const [sortBy, setSortBy] = useState('rating');
  const [selectedRestaurant, setSelectedRestaurant] = useState(null);

  useEffect(() => {
    loadRestaurants();
  }, []);

  const loadRestaurants = async () => {
    try {
      const response = await restaurantAPI.getAll();
      setRestaurants(response.data);
    } catch (error) {
      console.error('Error loading restaurants:', error);
    }
  };

  const filteredRestaurants = restaurants
    .filter(r => {
      const matchesSearch = r.name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
                           r.address?.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesFilter = filterType === 'all' || 
                           (filterType === 'veg' && r.veg) ||
                           (filterType === 'nonveg' && r.nonVeg);
      return matchesSearch && matchesFilter;
    })
    .sort((a, b) => {
      if (sortBy === 'rating') return (b.rating || 0) - (a.rating || 0);
      if (sortBy === 'name') return a.name?.localeCompare(b.name);
      return 0;
    });

  const bannerOffers = [
    { title: "50% OFF", subtitle: "On your first order", bg: "from-purple-500 to-pink-500" },
    { title: "Free Delivery", subtitle: "Orders above ₹299", bg: "from-green-500 to-blue-500" },
    { title: "Weekend Special", subtitle: "Extra 20% OFF", bg: "from-orange-500 to-red-500" }
  ];

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <header className="bg-white shadow-sm sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-16">
            <div className="flex items-center space-x-4">
              <h1 className="text-2xl font-bold bg-gradient-to-r from-orange-500 to-red-500 bg-clip-text text-transparent">
                🍔 SnackSmart
              </h1>
            </div>
            <div className="flex items-center space-x-4">
              <span className="text-gray-700">Welcome, {user.username}!</span>
              <motion.button
                whileHover={{ scale: 1.05 }}
                onClick={onLogout}
                className="bg-gradient-to-r from-red-500 to-pink-500 text-white px-4 py-2 rounded-lg font-medium shadow-md hover:shadow-lg transition-all"
              >
                Logout
              </motion.button>
            </div>
          </div>
        </div>
      </header>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Banner Carousel */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8">
          {bannerOffers.map((offer, index) => (
            <motion.div
              key={index}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: index * 0.1 }}
              className={`bg-gradient-to-r ${offer.bg} rounded-2xl p-6 text-white`}
            >
              <h3 className="text-2xl font-bold">{offer.title}</h3>
              <p className="text-white/90">{offer.subtitle}</p>
            </motion.div>
          ))}
        </div>

        {/* Search and Filters */}
        <div className="bg-white rounded-2xl shadow-sm p-6 mb-8">
          <div className="flex flex-col md:flex-row gap-4">
            <div className="relative flex-1">
              <MagnifyingGlassIcon className="absolute left-3 top-1/2 transform -translate-y-1/2 h-5 w-5 text-gray-400" />
              <input
                type="text"
                placeholder="Search restaurants..."
                className="w-full pl-10 pr-4 py-3 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-orange-500 focus:border-transparent"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
            <select
              className="px-4 py-3 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-orange-500"
              value={filterType}
              onChange={(e) => setFilterType(e.target.value)}
            >
              <option value="all">All Restaurants</option>
              <option value="veg">Veg Only</option>
              <option value="nonveg">Non-Veg</option>
            </select>
            <select
              className="px-4 py-3 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-orange-500"
              value={sortBy}
              onChange={(e) => setSortBy(e.target.value)}
            >
              <option value="rating">Sort by Rating</option>
              <option value="name">Sort by Name</option>
            </select>
          </div>
        </div>

        {/* Restaurant Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredRestaurants.map((restaurant, index) => (
            <motion.div
              key={restaurant.id}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: index * 0.1 }}
              whileHover={{ y: -5 }}
              className="bg-white rounded-2xl shadow-lg hover:shadow-xl transition-all duration-300 overflow-hidden cursor-pointer"
              onClick={() => setSelectedRestaurant(restaurant)}
            >
              <div className="relative h-48 bg-gradient-to-br from-orange-400 to-red-500">
                {restaurant.imageUrl ? (
                  <img
                    src={restaurant.imageUrl}
                    alt={restaurant.name}
                    className="w-full h-full object-cover"
                    onError={(e) => {
                      e.target.style.display = 'none';
                    }}
                  />
                ) : (
                  <div className="flex items-center justify-center h-full text-white text-6xl">
                    🍽️
                  </div>
                )}
                <div className="absolute top-4 right-4">
                  {restaurant.veg && restaurant.nonVeg ? (
                    <span className="bg-white/90 px-2 py-1 rounded-full text-xs font-medium">
                      🌿🍗 Both
                    </span>
                  ) : restaurant.veg ? (
                    <span className="bg-green-100 text-green-800 px-2 py-1 rounded-full text-xs font-medium">
                      🌿 Veg
                    </span>
                  ) : (
                    <span className="bg-red-100 text-red-800 px-2 py-1 rounded-full text-xs font-medium">
                      🍗 Non-Veg
                    </span>
                  )}
                </div>
              </div>

              <div className="p-6">
                <h3 className="text-xl font-bold text-gray-900 mb-2">{restaurant.name}</h3>

                <div className="flex items-center text-gray-600 mb-2">
                  <MapPinIcon className="h-4 w-4 mr-1" />
                  <span className="text-sm">{restaurant.address}</span>
                </div>

                <div className="flex items-center text-gray-600 mb-3">
                  <PhoneIcon className="h-4 w-4 mr-1" />
                  <span className="text-sm">{restaurant.phone}</span>
                </div>

                <div className="flex items-center justify-between">
                  <div className="flex items-center">
                    <StarIcon className="h-5 w-5 text-yellow-400 mr-1" />
                    <span className="font-semibold">{restaurant.rating || '4.0'}</span>
                    <span className="text-gray-500 ml-1">({Math.floor(Math.random() * 100) + 50})</span>
                  </div>
                  <motion.button
                    whileHover={{ scale: 1.05 }}
                    whileTap={{ scale: 0.95 }}
                    className="bg-gradient-to-r from-orange-500 to-red-500 text-white px-4 py-2 rounded-lg font-medium text-sm shadow-md hover:shadow-lg transition-all"
                  >
                    View Menu
                  </motion.button>
                </div>
              </div>
            </motion.div>
          ))}
        </div>

        {filteredRestaurants.length === 0 && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="text-center py-16"
          >
            <div className="text-6xl mb-4">🔍</div>
            <h3 className="text-xl font-semibold text-gray-900 mb-2">No restaurants found</h3>
            <p className="text-gray-600">Try adjusting your search or filters</p>
          </motion.div>
        )}

        {/* Restaurant Menu Modal */}
        {selectedRestaurant && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50"
            onClick={() => setSelectedRestaurant(null)}
          >
            <motion.div
              initial={{ scale: 0.9, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              className="bg-white rounded-2xl max-w-2xl w-full max-h-[80vh] overflow-y-auto"
              onClick={(e) => e.stopPropagation()}
            >
              <div className="p-6">
                <div className="flex justify-between items-start mb-6">
                  <div>
                    <h2 className="text-2xl font-bold text-gray-900">{selectedRestaurant.name}</h2>
                    <p className="text-gray-600">{selectedRestaurant.address}</p>
                  </div>
                  <button
                    onClick={() => setSelectedRestaurant(null)}
                    className="text-gray-400 hover:text-gray-600 text-2xl"
                  >
                    ×
                  </button>
                </div>

                <div className="space-y-4">
                  <h3 className="text-lg font-semibold">Menu</h3>
                  {selectedRestaurant.menu && selectedRestaurant.menu.length > 0 ? (
                    selectedRestaurant.menu.map((dish, index) => (
                      <div key={index} className="flex justify-between items-center p-4 bg-gray-50 rounded-xl">
                        <div>
                          <h4 className="font-medium">{dish.dishName}</h4>
                          <span className="text-sm text-gray-600">
                            {dish.veg ? '🌿 Veg' : '🍗 Non-Veg'}
                          </span>
                        </div>
                        <div className="text-right">
                          <div className="font-bold text-green-600">₹{dish.price}</div>
                          <button className="bg-orange-500 text-white px-3 py-1 rounded-lg text-sm mt-1 hover:bg-orange-600 transition-colors">
                            Add to Cart
                          </button>
                        </div>
                      </div>
                    ))
                  ) : (
                    <p className="text-gray-500 text-center py-8">No menu items available</p>
                  )}
                </div>
              </div>
            </motion.div>
          </motion.div>
        )}
      </div>
    </div>
  );
};

export default CustomerDashboard;
